async function engine(worksheet, childFilepath, src_sheet, dst_sheets) {
    try {
        const childbook = new ExcelJS.Workbook();
        await childbook.xlsx.readFile(childFilepath);

        for(let i = 0; i < dst_sheets.length; i++) {
            const childSheet = childbook.getWorksheet(dst_sheets[i].name);
            const startRow = dst_sheets[i].rows[0];
            const endRow = dst_sheets[i].rows[1];

            for (let i = startRow; i <= endRow; i++) {
                const row = worksheet.getRow(i);
                const childRow = childSheet.getRow(i - startRow + 1);

                row.eachCell((cell, colNumber) => {
                    let childCell = childRow.getCell(colNumber);
                    childCell = cell
                    console.log('cell value:', cell.value,  typeof cell.value, '=====', cell.type);
                });

                childRow.commit();
            }
            console.log('Sheet copied:', dst_sheets[i].name);
        }
        // Save the modified child sheet
        await childbook.xlsx.writeFile(childFilepath);
        console.log('Child file saved');
    } catch (error) {
        console.log('Error:', error);
    }
}

